// // This module is designed to be a 4-bit synchronous down-counter with a synchronous reset signal.
module up_counter(
    input wire clk,
    input wire rst,
    output reg [3:0] count
);

    always @(posedge clk) begin
        if (rst) begin
            count <= 4'b0000;
        end else begin
            count <= count + 1;
        end
    end
endmodule
